parameters.jsCode:
return [{
  json: {
    apiBaseUrl: 'https://nordkone.vercel.app',
    apiKey: 'RapidScreenNordKone',
    wasupSendUrl: 'https://wasup2.northeurope.cloudapp.azure.com/api/send',
    fromPhone: '358454913025',
    // Fill this with your own phone for the first end-to-end test.
    // Leave empty before launch so real seller numbers are used.
    testRecipientPhone: '2347067131336',
    candidateLimit: 1
  }
}];

const config = $('Workflow Config').first().json;
const candidate = $json.candidates?.[0];
if (!candidate) {
  return [];
}
const testRecipientPhone = String(config.testRecipientPhone || '').trim();
const toPhone = testRecipientPhone || candidate.normalized_phone;
return [{
  json: {
    ...candidate,
    config,
    is_test_send: Boolean(testRecipientPhone),
    original_seller_phone: candidate.normalized_phone,
    send_to_phone: toPhone,
    wasupPayload: {
      from_phone: config.fromPhone,
      to_phone: toPhone,
      message: candidate.outbound_message
    }
  }
}];

